item.content:encoded:
.single-tribe_events .tribe-events-single .tribe-events-event-meta{width:100%;}

.site-footer-wrap .wp-block-button a:hover{
	color: #32373c!important;
	text-decoration: none;
}


.kadence-ticker-wrapper {
    background: #000;
    height: 35px;
    overflow: hidden;
    position: relative;
    width: 100%;
}

.kadence-ticker {
    display: inline-block;
    white-space: nowrap;
    padding-left: 50%;
    animation: ticker 35s linear infinite;
}

.kadence-ticker span {
    color: #ED8F0C;
    font-family: 'Rajdhani', sans-serif;
    font-weight: 600;
    font-size: 16px;
    line-height: 35px;
    padding: 0 25px;
    display: inline-block;
    text-transform: uppercase;
    letter-spacing: 1.5px;
}

@keyframes ticker {
    0% { transform: translateX(0); }
    100% { transform: translateX(-100%); }
}

/* Mobil cihazlar için yeni yaklaşım */
@media screen and (max-width: 768px) {
    .kadence-ticker {
        animation: none; /* Önce animasyonu kaldırıyoruz */
        padding-left: 0; /* Padding'i sıfırlıyoruz */
        transform: translateX(0); /* Başlangıç pozisyonunu sıfırlıyoruz */
    }

    .kadence-ticker span {
        font-size: 14px;
        padding: 0 15px;
    }
}

/* Mobil için JavaScript ile animasyon */
@media screen and (max-width: 768px) {
    .kadence-ticker {
        animation: ticker-mobile 15s linear infinite;
    }
}

@keyframes ticker-mobile {
    0% { transform: translateX(100%); }
    100% { transform: translateX(-100%); }
}

